/// Check for orphaned files in the cache directory
fn check_orphaned_files(
    cache_dir: &Path,
    metadata: &CacheMetadata,
    orphaned: &mut Vec<PathBuf>,
) -> Result<()> {
    check_orphaned_files_recursive(cache_dir, cache_dir, metadata, orphaned)
}

/// Recursively check for orphaned files
fn check_orphaned_files_recursive(
    cache_dir: &Path,
    current_dir: &Path,
    metadata: &CacheMetadata,
    orphaned: &mut Vec<PathBuf>,
) -> Result<()> {
    if !current_dir.is_dir() {
        return Ok(());
    }

    for entry in fs::read_dir(current_dir)? {
        let entry = entry?;
        let path = entry.path();

        // Skip cache_metadata.json
        if path.file_name() == Some(std::ffi::OsStr::new("cache_metadata.json")) {
            continue;
        }

        if path.is_file() {
            // Get relative path from cache root
            if let Ok(relative_path) = path.strip_prefix(cache_dir) {
                if !metadata.is_cached(relative_path) {
                    orphaned.push(relative_path.to_path_buf());
                }
            }
        } else if path.is_dir() {
            // Recurse into subdirectories
            check_orphaned_files_recursive(cache_dir, &path, metadata, orphaned)?;
        }
    }

    Ok(())
}

