//! Local cache management
//!
//! This module handles the local file cache for downloaded templates.
//! 
//! The cache is organized with the following structure:
//! ```
//! ~/.cache/templateflow/
//! ├── templateflow-skel.zip       # Template index/skeleton
//! ├── templateflow-skel.md5       # Checksum for skeleton
//! ├── tpl-MNI152Lin/             # Template directories
//! │   ├── template_description.json
//! │   └── tpl-MNI152Lin_res-01_T1w.nii.gz
//! └── cache_metadata.json         # Cache metadata (timestamps, etc.)
//! ```

use crate::config::{Config, CONFIG};
use crate::error::{Result, TemplateFlowError};
use serde::{Deserialize, Serialize};
use std::collections::HashMap;
use std::fs;
use std::path::{Path, PathBuf};
use std::time::{Duration, SystemTime, UNIX_EPOCH};

/// Metadata for cached files
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CacheEntry {
    /// Path relative to cache root
    pub path: PathBuf,
    /// Size in bytes
    pub size: u64,
    /// Unix timestamp of when the file was cached
    pub cached_at: u64,
    /// Optional checksum (MD5 or SHA256)
    pub checksum: Option<String>,
    /// Source URL
    pub source_url: Option<String>,
}

/// Cache metadata storage
#[derive(Debug, Clone, Serialize, Deserialize, Default)]
pub struct CacheMetadata {
    /// Version of the cache metadata format
    pub version: u32,
    /// Map of relative paths to cache entries
    pub entries: HashMap<PathBuf, CacheEntry>,
    /// Last update timestamp
    pub last_updated: u64,
}

impl CacheMetadata {
    /// Current metadata version
    const CURRENT_VERSION: u32 = 1;

    /// Create new cache metadata
    pub fn new() -> Self {
        Self {
            version: Self::CURRENT_VERSION,
            entries: HashMap::new(),
            last_updated: current_timestamp(),
        }
    }

    /// Load metadata from cache directory
    pub fn load(cache_dir: &Path) -> Result<Self> {
        let metadata_path = cache_dir.join("cache_metadata.json");
        if !metadata_path.exists() {
            return Ok(Self::new());
        }

        let content = fs::read_to_string(&metadata_path)?;
        let metadata: Self = serde_json::from_str(&content)
            .map_err(|e| TemplateFlowError::CacheError(format!("Failed to parse cache metadata: {}", e)))?;

        Ok(metadata)
    }

    /// Save metadata to cache directory
    pub fn save(&self, cache_dir: &Path) -> Result<()> {
        let metadata_path = cache_dir.join("cache_metadata.json");
        let content = serde_json::to_string_pretty(self)
            .map_err(|e| TemplateFlowError::CacheError(format!("Failed to serialize cache metadata: {}", e)))?;

        fs::write(&metadata_path, content)?;
        Ok(())
    }

    /// Add or update a cache entry
    pub fn update_entry(&mut self, relative_path: PathBuf, entry: CacheEntry) {
        self.entries.insert(relative_path, entry);
        self.last_updated = current_timestamp();
    }

    /// Remove a cache entry
    pub fn remove_entry(&mut self, relative_path: &Path) -> Option<CacheEntry> {
        let removed = self.entries.remove(relative_path);
        if removed.is_some() {
            self.last_updated = current_timestamp();
        }
        removed
    }

    /// Check if a file is cached
    pub fn is_cached(&self, relative_path: &Path) -> bool {
        self.entries.contains_key(relative_path)
    }

    /// Get cache entry for a path
    pub fn get_entry(&self, relative_path: &Path) -> Option<&CacheEntry> {
        self.entries.get(relative_path)
    }
}

/// Cache manager for template files
pub struct Cache {
    /// Configuration
    config: Config,
    /// Cache metadata
    metadata: CacheMetadata,
}

impl Cache {
    /// Create a new cache manager
    pub fn new(config: Config) -> Result<Self> {
        // Ensure cache directory exists
        config.ensure_home_exists()?;

        // Load existing metadata
        let metadata = CacheMetadata::load(&config.home)?;

        Ok(Self { config, metadata })
    }

    /// Create cache manager with default config
    pub fn default() -> Result<Self> {
        Self::new(CONFIG.clone())
    }

    /// Get the cache directory path
    pub fn cache_dir(&self) -> &Path {
        &self.config.home
    }

    /// Get full path for a cached file
    pub fn get_cached_path(&self, relative_path: &Path) -> PathBuf {
        self.config.home.join(relative_path)
    }

    /// Check if a file exists in cache
    pub fn exists(&self, relative_path: &Path) -> bool {
        let full_path = self.get_cached_path(relative_path);
        full_path.exists() && self.metadata.is_cached(relative_path)
    }

    /// Add a file to the cache metadata
    pub fn add_file(&mut self, relative_path: &Path, source_url: Option<String>) -> Result<()> {
        let full_path = self.get_cached_path(relative_path);

        if !full_path.exists() {
            return Err(TemplateFlowError::CacheError(
                format!("File does not exist: {}", full_path.display())
            ));
        }

        let metadata = fs::metadata(&full_path)?;
        let entry = CacheEntry {
            path: relative_path.to_path_buf(),
            size: metadata.len(),
            cached_at: current_timestamp(),
            checksum: None, // TODO: Calculate checksum if needed
            source_url,
        };

        self.metadata.update_entry(relative_path.to_path_buf(), entry);
        self.metadata.save(&self.config.home)?;

        Ok(())
    }

    /// Remove a file from cache
    pub fn remove_file(&mut self, relative_path: &Path) -> Result<()> {
        let full_path = self.get_cached_path(relative_path);

        // Remove from filesystem if exists
        if full_path.exists() {
            fs::remove_file(&full_path)?;
        }

        // Remove from metadata
        self.metadata.remove_entry(relative_path);
        self.metadata.save(&self.config.home)?;

        Ok(())
    }

    /// Get all cached files for a template
    pub fn get_template_files(&self, template: &str) -> Vec<PathBuf> {
        let template_prefix = format!("tpl-{}/", template);

        self.metadata.entries
            .keys()
            .filter(|path| {
                path.to_str()
                    .map(|s| s.starts_with(&template_prefix))
                    .unwrap_or(false)
            })
            .cloned()
            .collect()
    }

    /// Get total cache size in bytes
    pub fn total_size(&self) -> u64 {
        self.metadata.entries.values().map(|e| e.size).sum()
    }

    /// Get number of cached files
    pub fn file_count(&self) -> usize {
        self.metadata.entries.len()
    }

    /// Clear all cache entries (but keep the directory)
    pub fn clear(&mut self) -> Result<()> {
        // Remove all files except cache_metadata.json
        for entry in self.metadata.entries.values() {
            let full_path = self.get_cached_path(&entry.path);
            if full_path.exists() {
                fs::remove_file(&full_path)?;
            }
        }

        // Clear metadata
        self.metadata.entries.clear();
        self.metadata.last_updated = current_timestamp();
        self.metadata.save(&self.config.home)?;

        Ok(())
    }

    /// Remove empty directories in the cache
    pub fn cleanup_empty_dirs(&self) -> Result<()> {
        cleanup_empty_directories(&self.config.home)?;
        Ok(())
    }

    /// Validate a cached file
    pub fn validate_file(&self, relative_path: &Path) -> Result<bool> {
        // Check if file exists in metadata
        if let Some(entry) = self.metadata.get_entry(relative_path) {
            let full_path = self.get_cached_path(relative_path);

            // Check if file exists on disk
            if !full_path.exists() {
                return Ok(false);
            }

            // Check file size matches
            let metadata = fs::metadata(&full_path)?;
            if metadata.len() != entry.size {
                return Ok(false);
            }

            // TODO: Check checksum if available
            if entry.checksum.is_some() {
                // Implement checksum validation when we add checksum calculation
            }

            Ok(true)
        } else {
            Ok(false)
        }
    }

    /// Check if a cached file is stale (older than specified duration)
    pub fn is_stale(&self, relative_path: &Path, max_age: Duration) -> bool {
        if let Some(entry) = self.metadata.get_entry(relative_path) {
            let age = current_timestamp() - entry.cached_at;
            age > max_age.as_secs()
        } else {
            true // Consider non-existent files as stale
        }
    }

    /// Get cache statistics
    pub fn get_stats(&self) -> CacheStats {
        let total_size = self.total_size();
        let file_count = self.file_count();
        let templates = self.get_cached_templates();

        CacheStats {
            total_size,
            file_count,
            template_count: templates.len(),
            last_updated: self.metadata.last_updated,
        }
    }

    /// Get list of cached templates
    pub fn get_cached_templates(&self) -> Vec<String> {
        let mut templates = std::collections::HashSet::new();

        for path in self.metadata.entries.keys() {
            if let Some(path_str) = path.to_str() {
                if path_str.starts_with("tpl-") {
                    if let Some(template) = path_str.split('/').next() {
                        if let Some(name) = template.strip_prefix("tpl-") {
                            templates.insert(name.to_string());
                        }
                    }
                }
            }
        }

        let mut result: Vec<_> = templates.into_iter().collect();
        result.sort();
        result
    }

    /// Verify cache integrity
    pub fn verify_integrity(&self) -> Result<CacheVerificationReport> {
        let mut missing_files = Vec::new();
        let mut size_mismatches = Vec::new();
        let mut orphaned_files = Vec::new();

        // Check all entries in metadata
        for (relative_path, entry) in &self.metadata.entries {
            let full_path = self.get_cached_path(relative_path);

            if !full_path.exists() {
                missing_files.push(relative_path.clone());
            } else {
                let metadata = fs::metadata(&full_path)?;
                if metadata.len() != entry.size {
                    size_mismatches.push((relative_path.clone(), entry.size, metadata.len()));
                }
            }
        }

        // Check for orphaned files (files on disk but not in metadata)
        check_orphaned_files(&self.config.home, &self.metadata, &mut orphaned_files)?;

        Ok(CacheVerificationReport {
            missing_files,
            size_mismatches,
            orphaned_files,
            total_errors: missing_files.len() + size_mismatches.len() + orphaned_files.len(),
        })
    }

    /// Fix cache integrity issues
    pub fn fix_integrity_issues(&mut self, report: &CacheVerificationReport) -> Result<()> {
        // Remove missing files from metadata
        for path in &report.missing_files {
            self.metadata.remove_entry(path);
        }

        // Update sizes for mismatched files
        for (path, _, actual_size) in &report.size_mismatches {
            if let Some(entry) = self.metadata.entries.get_mut(path) {
                entry.size = *actual_size;
            }
        }

        // Add orphaned files to metadata
        for path in &report.orphaned_files {
            if let Ok(metadata) = fs::metadata(&self.config.home.join(path)) {
                let entry = CacheEntry {
                    path: path.clone(),
                    size: metadata.len(),
                    cached_at: current_timestamp(),
                    checksum: None,
                    source_url: None,
                };
                self.metadata.update_entry(path.clone(), entry);
            }
        }

        self.metadata.save(&self.config.home)?;
        Ok(())
    }
}

/// Cache statistics
#[derive(Debug, Clone, Serialize, Deserialize)]
pub struct CacheStats {
    /// Total size of cached files in bytes
    pub total_size: u64,
    /// Number of cached files
    pub file_count: usize,
    /// Number of cached templates
    pub template_count: usize,
    /// Last update timestamp
    pub last_updated: u64,
}

/// Cache verification report
#[derive(Debug)]
pub struct CacheVerificationReport {
    /// Files in metadata but missing from disk
    pub missing_files: Vec<PathBuf>,
    /// Files with size mismatches (path, expected, actual)
    pub size_mismatches: Vec<(PathBuf, u64, u64)>,
    /// Files on disk but not in metadata
    pub orphaned_files: Vec<PathBuf>,
    /// Total number of errors found
    pub total_errors: usize,
}

/// Get current Unix timestamp
fn current_timestamp() -> u64 {
    SystemTime::now()
        .duration_since(UNIX_EPOCH)
        .unwrap_or_default()
        .as_secs()
}

/// Recursively remove empty directories
fn cleanup_empty_directories(dir: &Path) -> Result<()> {
    if !dir.is_dir() {
        return Ok(());
    }

    let entries: Vec<_> = fs::read_dir(dir)?
        .filter_map(|e| e.ok())
        .collect();

    // Process subdirectories first
    for entry in &entries {
        if entry.file_type()?.is_dir() {
            cleanup_empty_directories(&entry.path())?;
        }
    }

    // Check if directory is now empty (except for cache_metadata.json)
    let remaining_entries: Vec<_> = fs::read_dir(dir)?
        .filter_map(|e| e.ok())
        .filter(|e| {
            e.file_name() != "cache_metadata.json"
        })
        .collect();

    if remaining_entries.is_empty() && dir.file_name() != Some(std::ffi::OsStr::new("templateflow")) {
        fs::remove_dir(dir)?;
    }

    Ok(())
}

